-- 1. DATABASE 유형 권한 분석 정책 생성
BEGIN
  DBMS_PRIVILEGE_CAPTURE.CREATE_CAPTURE(
    name        => 'full_db_priv_analysis',
    type        => DBMS_PRIVILEGE_CAPTURE.G_DATABASE,
    description => 'Full database privilege analysis'
  );
END;
/

-- 2. 캡처 활성화
BEGIN
  DBMS_PRIVILEGE_CAPTURE.ENABLE_CAPTURE(
    name => 'full_db_priv_analysis'
  );
END;
/

-- 3. (워크로드 실행 기간 - 일반 업무 수행)

-- 4. 캡처 비활성화
BEGIN
  DBMS_PRIVILEGE_CAPTURE.DISABLE_CAPTURE(
    name => 'full_db_priv_analysis'
  );
END;
/

-- 5. 결과 생성
BEGIN
  DBMS_PRIVILEGE_CAPTURE.GENERATE_RESULT(
    name => 'full_db_priv_analysis'
  );
END;
/

-- 특정 역할(DBA, RESOURCE)에 대한 권한 분석 정책 생성
BEGIN
  DBMS_PRIVILEGE_CAPTURE.CREATE_CAPTURE(
    name        => 'role_priv_analysis',
    type        => DBMS_PRIVILEGE_CAPTURE.G_ROLE,
    roles       => role_name_list('DBA', 'RESOURCE'),
    description => 'Analyze DBA and RESOURCE role usage'
  );
END;
/

-- 기존 프로파일 파라미터 변경
ALTER PROFILE dev_profile LIMIT
  IDLE_TIME        60
  CONNECT_TIME     600;

-- DEFAULT 프로파일의 비밀번호 정책 변경
ALTER PROFILE DEFAULT LIMIT
  PASSWORD_LIFE_TIME      180
  FAILED_LOGIN_ATTEMPTS   10
  PASSWORD_LOCK_TIME      1
  PASSWORD_VERIFY_FUNCTION ora12c_verify_function;

-- 사용자에게 프로파일 할당
ALTER USER scott PROFILE dev_profile;
ALTER USER hr_user PROFILE secure_pwd_profile;

-- 계정 수동 잠금
ALTER USER scott ACCOUNT LOCK;

-- 계정 수동 해제
ALTER USER scott ACCOUNT UNLOCK;

-- 비밀번호 즉시 만료 설정 (다음 로그인 시 변경 강제)
ALTER USER scott PASSWORD EXPIRE;

-- 잠금 및 만료 상태 확인
SELECT username, account_status, lock_date, 
       expiry_date, last_login
FROM dba_users
WHERE username = 'SCOTT';

-- LOCKED(TIMED) 상태 사용자 확인 (자동 잠금된 계정)
SELECT username, account_status, lock_date
FROM dba_users
WHERE account_status LIKE '%LOCKED(TIMED)%';

-- UNLIMITED TABLESPACE 시스템 권한 부여
GRANT UNLIMITED TABLESPACE TO app_user;

-- UNLIMITED TABLESPACE 권한 회수 (개별 쿼터가 다시 적용됨)
REVOKE UNLIMITED TABLESPACE FROM app_user;

-- UNLIMITED TABLESPACE 권한 보유 여부 확인
SELECT grantee, privilege
FROM dba_sys_privs
WHERE privilege = 'UNLIMITED TABLESPACE'
ORDER BY grantee;
